properties.defaultValue:
precision highp float;
varying vec2 vUv;
uniform vec2 uResolution;
uniform float uTime;
uniform float uFlipY;

void main() {
	vec2 uv = vUv;
	if (uFlipY < 0.5) uv.y = 1.0 - uv.y;
	vec2 p = (uv * uResolution) / max(1.0, min(uResolution.x, uResolution.y));
	float v = 0.5 + 0.5 * sin(uTime + p.x * 0.1 + p.y * 0.1);
	gl_FragColor = vec4(vec3(v), 1.0);
}

varying vec2 vUv;
void main() {
	vUv = uv;
	gl_Position = vec4(position, 1.0);
}
